// src/react/rich-text/util/heading-id.ts
function extractTextFromNode(node) {
  let textContent = "";
  node?.content?.forEach((child) => {
    if (child.type === "text") {
      textContent += child.text;
    }
    if ("content" in child && child.content) {
      textContent += extractTextFromNode(child);
    }
  });
  return textContent;
}

export {
  extractTextFromNode
};
